mapper.select:
SELECT /* [SaleMng_SQL.xml][selectSaleMng] */ TO_CHAR(SALE_DATE , 'MM/DD/YYYY') AS SALE_DATE , SALE_SITE, SALE_ITEM, SALE_AMT, SALE_MANAGER, TO_CHAR(SALE_REG_DATE , 'MM/DD/YYYY') AS SALE_REG_DATE FROM SALE_MNG A WHERE 1 = 1
AND TO_CHAR(SALE_DATE, 'MMDDYYYY') = REPLACE(#{saleDate},'/','')
AND SALE_SITE = #{saleSite}
AND SALE_ITEM = #{saleItem}
AND SALE_AMT = #{saleAmt}
AND SALE_MANAGER = #{saleManager}
AND TO_CHAR(SALE_REG_DATE, 'MMDDYYYY') = REPLACE(#{saleRegDate},'/','')

mapper.update:
UPDATE /* [SaleMng_SQL.xml][updateSaleMng] */ SALE_MNG SET SALE_DATE = TO_DATE(REPLACE(#{saleDate} , '/','') , 'MM/DD/YYYY'), SALE_SITE = #{saleSite}, SALE_ITEM = #{saleItem}, SALE_AMT = #{saleAmt}, SALE_MANAGER = #{saleManager}, SALE_REG_DATE = TO_DATE(#{saleRegDate} , 'MM/DD/YYYY') WHERE 1=1
AND TO_CHAR(SALE_DATE, 'MMDDYYYY') = REPLACE( #{saleDateOld} , '/','')
AND SALE_SITE = #{saleSiteOld}
AND SALE_ITEM = #{saleItemOld}
AND SALE_AMT = #{saleAmtOld}
AND SALE_MANAGER = #{saleManagerOld}
AND TO_CHAR(SALE_REG_DATE, 'MMDDYYYY') = REPLACE( #{saleRegDateOld} , '/','')

mapper.delete:

DELETE FROM /* [SaleMng_SQL.xml][deleteSaleMng] */
  SALE_MNG
WHERE 1 = 1   

AND TO_CHAR(SALE_DATE, 'MMDDYYYY') = REPLACE( #{saleDate} , '/','')


AND SALE_SITE = #{saleSite}


AND SALE_ITEM = #{saleItem}


AND SALE_AMT = #{saleAmt}


AND SALE_MANAGER = #{saleManager}


AND TO_CHAR(SALE_REG_DATE, 'MMDDYYYY') = REPLACE( #{saleRegDate} , '/','')
